from docx import Document
from docx.shared import Pt, Inches
from docx.enum.text import WD_ALIGN_PARAGRAPH, WD_LINE_SPACING

def create_pirls_emptypot_student():
    doc = Document()
    for section in doc.sections:
        section.top_margin, section.bottom_margin = Inches(1), Inches(1)
        section.left_margin, section.right_margin = Inches(1), Inches(1)

    style = doc.styles['Normal']
    style.font.name = 'Arial'
    style.font.size = Pt(14)
    style.paragraph_format.line_spacing_rule = WD_LINE_SPACING.ONE_POINT_FIVE

    # НАСОКИ
    doc.add_heading('ДЕЛ 1: ТЕСТ-КНИШКА ЗА УЧЕНИКОТ', 1)
    doc.add_heading('НАСОКИ ЗА УЧЕНИКОТ', 2)
    doc.add_paragraph("Во овој тест, ќе прочитате приказни или написи и ќе одговорите на прашања за она што сте прочитале. Некои делови можеби ќе ви се лесни и можеби некои делови ќе ви се потешки. Ќе се побара од вас да одговорите на различни типови на прашања. Некои од прашањата ќе бидат проследени со четири опции. Вие ќе го одберете најдобриот одговор и ќе го пополните крукчето до одговорот. На некои од прашањата ќе треба да ги напишете вашите одговори во просторот предвиден во брошурата. Дадете сè од себе да ги одговориш сите прашања. Ако не можете да одговорите на некое прашање, преминете на следното.")
    doc.add_page_break()

    # ТЕКСТ
    doc.add_heading('ПРАЗНАТА САКСИЈА', 0).alignment = WD_ALIGN_PARAGRAPH.CENTER
    doc.add_paragraph("раскажана од Елеин Л. Линди").alignment = WD_ALIGN_PARAGRAPH.CENTER

    paragraphs = [
        "Царот на Кина објави натпревар за избор на следниот престолонаследник. Царот беше стар и немаше деца. Бидејќи сакаше растенија, тој изјави дека секое дете што сака да биде цар треба да дојде во палатата за да добие едно кралско семе. Кое дете ќе покаже најдобри резултати во рок од шест месеци, ќе победи на натпреварот и ќе стане следниот цар.",
        "Можете да ја замислите возбудата! На денот кога требаше да се дели семето, мноштво деца исполнети со надеж ја исполнија палатата. Секое дете се врати дома држејќи една драгоцена можност.",
        "Така беше и со момчето Јун. Тој веќе важеше за најдобар градинар во селото. Неговите соседи сакаа да земаат дињи, зелка и снежен грашок од неговата градина. Јун внимателно го носеше семето на Царот, чувајќи го безбедно во рацете за да не падне, но не толку цврсто за да може да се уништи.",
        "Дома, тој постави големи камења на дното на саксијата за цвеќе, ги покри камењата со ситни камчиња, а потоа го наполни садот со плодна влажна земја. Тој го притисна семето околу еден сантиметар под површината и го покри со лесна земја. Во периодот што следеше, Јун секој ден ја полеваше својата саксија и, како и секое дете што го познаваше, гледаше како првиот лист ќе избие на површината.",
        "Чеун беше првото дете во селото на Јун што објави дека неговото семе никнува. Ова беше дочекано со многу честитки. Тој се пофали дека сигурно ќе биде следниот цар и ги вежбаше своите кралски вештини шефувајќи им на помладите деца. Минг беше следното дете чие мало растение изникна од неговиот сад, а потоа и Вонг. Јун се збуни - ниту едно од овие момчиња не можеше да одгледува растенија како него! Но, семето на Јун не порасна.",
        "Наскоро се појавија никулци од саксиите низ целото село. Децата градеа огради околу нивните саксии и ги чуваа од оние што можеа случајно (или не толку случајно) да ги превртат. Набргу, десетици никулци во саксиите низ селото на Јун ги подаваа своите први лисја. Но, семето на Јун не порасна. Тој беше збунет и се прашуваше што не беше во ред? Јун внимателно го пресади своето семе во нова саксија со најдобрата и најплодната црна земја од неговата градина. Ја раздроби секоја топка земја во ситни честички. Нежно го притисна семето, го одржуваше горниот дел влажен и ја гледаше саксијата секој ден. Сепак семето на Јун не порасна.",
        "Наскоро се појавија силни, моќни стебленца од саксиите за кои се грижеа другите деца во селото на Јун. Јун беше тажен и разочаран. Другите деца му се смееја.",
        "Поминаа шест месеци. Се приближи денот кога децата требаше да ги донесат своите растенија во палатата за проверка. Тие ги чистеа садовите додека не заблескаа, нежно ги избришаа убавите лисја и се облекоа во нивната најубава облека. Некои родители одеа заедно со своето дете додека ја носеа саксијата до палатата, држејќи го растението исправено за да не се преврти.",
        "„Што ќе правам јас?“ - се жалеше Јун на неговите родители додека гледаше низ прозорецот кон другите деца кои се подготвуваа за нивното триумфално враќање во палатата. „Моето семе не сака да порасне! Саксијата ми е празна!“\n„Ти направи сè што можеше“, рече неговиот татко, одмавнувајќи со главата.\n„Јун, само однеси му ја на Царот твојата саксија“, рече неговата мајка, „тоа е сè што може да направиш“.",
        "Јун, засрамен, ја носеше својата празна саксија на патот кон палатата, додека веселите деца носеа саксии кои трепереа со огромни растенија, маршираа десно и лево од него.",
        "Во палатата, децата се редеа во редови со своите расцветани растенија и ја чекаа одлуката. Царот, завиткан во својата свилена наметка, тргна по низата надежни натпреварувачи, гледајќи го секое растение со намуртено лице. Кога дојде до Јун, тој уште повеќе се налути и рече: „Што е ова? Ти ми донесе празна саксија? “",
        "Сè што можеше Јун да стори е да се воздржи да не заплаче. „Но, ве молам, Ваше височество“, рече Јун, „се трудев да дадам сè од себе. Го засадив Вашето семе во најдобрата почва што можев да ја најдам, го чував влажно и го гледав секој ден. Кога семето не порасна, јас дури и го пресадив во нова земја. Но, тоа едноставно не порасна. Жал ми е.“ Јун ја наведна главата.",
        "„Хм“, рече Царот. Вртејќи се за да можат сите да слушнат, тој грмна: „Не знам од каде го добија семето сите овие други деца. Ништо не можеше да расте од семето што ви го дадов, бидејќи сите семиња беа варени!“\nИ Царот му се насмевна на Јун."
    ]

    for p in paragraphs:
        doc.add_paragraph(p).alignment = WD_ALIGN_PARAGRAPH.JUSTIFY

    doc.add_page_break()
    doc.add_heading('ПРАШАЊА ЗА ТЕКСТОТ', 1)

    mcq = {
        "1": ("Зошто Царот го организирал натпреварот?", ["а) да ги научи децата за растенија", "б) да го избере следниот цар", "в) да покаже колку е грандиозен", "г) да го открие најдобриот вид растение"]),
        "3": ("Зошто секое семе било наречено „драгоцена можност“?", ["а) Секое семе било шанса за да се победи во натпреварот.", "б) Секое семе било кралско и многу скапо.", "в) Секое семе ќе израснело во некое прекрасно растение.", "г) Секое семе било шанса да се стане најдобриот градинар."]),
        "5": ("Која саксија наликува најмногу на саксијата на Јун во која најпрво го засади семето?", ["а) Саксија со камења на дното", "б) Саксија само со земја", "в) Саксија со цвеќе", "г) Празна саксија"]),
        "6": ("Што се кажува во овој параграф за Јун?", ["а) дека се прашувал што ќе израсне", "б) дека мислел на победа на натпреварот", "в) дека го засадил семето со внимание", "г) дека направил грешки кога го засадил семето"]),
        "7": ("Зошто децата граделе огради околу нивните насади?", ["а) за да ги одржуваат чисти листовите", "б) за да ги заштитат растенијата од смачкување", "в) за да ја одржуваат земјата влажна", "г) за да ги спречат другите деца да ги гледаат нивните растенија"]),
        "8": ("Што била првата работа која ја направил Јун кога видел дека неговото семе не расте?", ["а) Изградил ограда околу неговата саксија.", "б) Почесто го наводнувал семето.", "в) Се пожалил на неговите родители.", "г) Го пресадил неговото семе во нова саксија."]),
        "11": ("Кој збор најдобро опишува како се чувствувал Јун кога влегол во палатата за да ја чуе одлуката?", ["а) засрамен", "б) збунет", "в) надежен", "г) возбуден"]),
        "12": ("Зошто Царот се намуртил кога ги гледал растенијата на другите деца?", ["а) Тој бил загрижен за натпреварот.", "б) Тој мислел дека саксијата на Јун не била доволно сјајна.", "в) Тој знаел дека мамат.", "г) Не му било јасно зошто Јун бил присутен."]),
        "13": ("Зошто Jун му рече: „Жал ми е“ на Царот?", ["а) мамел на натпреварот.", "б) не сакал да стане цар.", "в) мислел дека го разочарал Царот.", "г) премногу често го поливал неговото семе."]),
        "14": ("Зошто растенијата израснале во саксиите на другите деца?", ["а) другите деца користеле подобра почва.", "б) другите деца внимавале на своите саксии.", "в) нивните семиња биле заштитени со оградите.", "г) нивните семиња биле заменети со нови."]),
        "15": ("Што мислиш, што Царот најмногу ценел во некоја личност?", ["а) да има кралски квалитети", "б) да биде искрена личност", "в) да има почит кон своите родители", "г) да биде добар градинар"])
    }

    open_q = {
        "2": ("Што добило секое дете од Царот?", 1, 2),
        "4": ("Што покажува дека Jун бил најдобриот градинар во селото?", 1, 2),
        "9": ("Зошто другите деца му се смееле на Јун? Употреби го она што се случило во приказната за да го објасниш својот одговор.", 2, 3),
        "10": ("Што мислиш зошто родителите на Јун го посоветувале да ја однесе празната саксија во палатата?", 1, 2),
        "16": ("Зошто Царот му се насмевнал на Јун?", 1, 2)
    }

    for i in range(1, 18):
        num = str(i)
        if num in mcq:
            q, opts = mcq[num]
            doc.add_paragraph(f"{num}. {q}").runs[0].bold = True
            for o in opts:
                doc.add_paragraph(f"O  {o}").paragraph_format.left_indent = Inches(0.5)
        elif num in open_q:
            q, pts, lines = open_q[num]
            p = doc.add_paragraph()
            p.add_run(f"{num}. {q}").bold = True
            p.add_run(f" [✎ {pts} поен/и]").italic = True
            for _ in range(lines):
                doc.add_paragraph("_" * 60)
        elif num == "17":
            doc.add_paragraph("17. Јун имал различни чувства низ целата приказна. Искористи го она кое го прочита за да објасниш зошто Јун го имал секое од овие чувства.").runs[0].bold = True
            doc.add_paragraph("Надежен: [1 поен]\n" + "_"*60 + "\n" + "_"*60)
            doc.add_paragraph("Збунет: [1 поен]\n" + "_"*60 + "\n" + "_"*60)
            doc.add_paragraph("Поразен: [1 поен]\n" + "_"*60 + "\n" + "_"*60)

    doc.add_paragraph("\n🛑 СТОП. КРАЈ НА ТЕСТОТ.")
    doc.save("PIRLS_Test_EmptyPot_Ucenik.docx")

if __name__ == "__main__":
    create_pirls_emptypot_student()
